import pytest

def execute(code, **kwargs):
    return run_in_container(code, **kwargs)

class TestSandboxSecurity:
    def test_dunder_traversal_blocked(self):
        r = execute("print(().__class__.__bases__[0].__subclasses__())")
        assert r["returncode"] != 0 or "subclasses" not in r.get("stdout", "")

    def test_os_import_blocked(self):
        r = execute("import os; os.system('id')")
        assert r["returncode"] != 0

    def test_subprocess_blocked(self):
        r = execute("import subprocess; subprocess.run(['id'])")
        assert r["returncode"] != 0

    def test_shell_absent(self):
        r = execute("import subprocess; subprocess.run(['/bin/bash', '-c', 'id'])")
        assert r["returncode"] != 0

    def test_filesystem_read_only(self):
        r = execute("open('/usr/lib/attack.py', 'w').write('x')")
        assert r["returncode"] != 0

    def test_tmp_noexec(self):
        r = execute(
            "import subprocess\n"
            "open('/tmp/x.sh', 'w').write('#!/bin/sh\necho hi')\n"
            "subprocess.run(['/tmp/x.sh'])"
        )
        assert r["returncode"] != 0

    def test_network_blocked(self):
        r = execute(
            "import socket\n"
            "socket.create_connection(('8.8.8.8', 53), timeout=2)"
        )
        assert r["returncode"] != 0

    def test_fork_bomb_limited(self):
        r = execute("import os\nfor _ in range(200):\n    os.fork()", timeout=5)
        assert r["returncode"] != 0

    def test_memory_bomb_limited(self):
        r = execute("x = bytearray(300 * 1024 * 1024)")
        assert r["returncode"] != 0

    def test_safe_computation_passes(self):
        r = execute("import math; print(math.factorial(20))")
        assert r["error"] is None
        assert "2432902008176640000" in r["stdout"]
